import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Instalando Fabric","description":"Um guia passo a passo de como instalar Fabric.","frontmatter":{"title":"Instalando Fabric","description":"Um guia passo a passo de como instalar Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pt_br/1.21.4/players/installing-fabric.md","filePath":"versions/1.21.4/translated/pt_br/players/installing-fabric.md","lastUpdated":1760721669000}`);var c={name:`pt_br/1.21.4/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalando Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalando Fabric”">​</a></h1><p>Este guia o orientará na instalação do Fabric para o Launcher oficial do Minecraft.</p><p>Para launchers de terceiros, você deve consultar suas devidas documentações.</p><h2 id="_1-baixar-o-instalador-do-fabric" tabindex="-1">1. Baixar o instalador do Fabric <a class="header-anchor" href="#_1-baixar-o-instalador-do-fabric" aria-label="Permalink to “1. Baixar o instalador do Fabric”">​</a></h2><p>Você pode baixar o Instalador do Fabric pelo <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Site do Fabric</a>.</p><p>Se você usa Windows, baixe a versão <code>.exe</code> (<code>Download For Windows</code>), pois ela não necessita da presença do Java no seu sistema. Ela usa o Java que acompanha o launcher oficial.</p><p>Para macOS e Linux, você deve baixar a versão <code>.jar</code>. A instalação do Java antes desse passo pode ser necessária.</p><h2 id="_2-executar-o-instalador-do-fabric" tabindex="-1">2. Executar o instalador do Fabric <a class="header-anchor" href="#_2-executar-o-instalador-do-fabric" aria-label="Permalink to “2. Executar o instalador do Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Feche o Minecraft e Minecraft Launcher antes da instalação.</p></div><details class="details custom-block"><summary>Informação para usuários do macOS</summary><p>No macOS, talvez seja necessário clicar com o botão direito no arquivo <code>.jar</code> em sua pasta de downloads e clicar em <code>Open</code> para executá-lo.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Menu de contexto do macOS no Instalador do Fabric" loading="lazy"></p><p>Quando perguntado &quot;Tem certeza de que deseja abrir isso?&quot;, aperte em <code>Abrir</code> novamente.</p></details><p>Assim que você abrir o instalador, deverá ver uma tela como essa:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Instalador do Fabric com &quot;Instalar&quot; destacado" loading="lazy"></p><p>Para instalar o Fabric, apenas escolha a versão do seu jogo e clique em <code>Instalar</code>.</p><p><strong>Certifique-se de que <code>Criar Perfil</code> está marcado.</strong></p><h2 id="_3-tudo-pronto" tabindex="-1">3. Tudo Pronto! <a class="header-anchor" href="#_3-tudo-pronto" aria-label="Permalink to “3. Tudo Pronto!”">​</a></h2><p>Assim que o instalador terminar, você pode abrir o Minecraft Launcher, selecionar o perfil Fabric através do botão no canto inferior esquerdo e clicar em Jogar!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher com o perfil Fabric selecionado" loading="lazy"></p><h2 id="proximos-passos" tabindex="-1">Próximos passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to “Próximos passos”">​</a></h2><p>Agora que você instalou o Fabric, você pode adicionar mods ao seu jogo! Dê uma olhada no guia <a href="./finding-mods">Encontrando Mods Confiáveis</a> para mais informações.</p><p>Se você encontrar algum problema, sinta-se à vontade para pedir ajuda no <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p>`,20)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};